index 394dfca262e1..e0680f312ba4 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp
@@ -3090,6 +3090,54 @@ static Instruction *foldNestedSelects(SelectInst &OuterSelVal,
                             !IsAndVariant ? SelInner : InnerSel.FalseVal);
 }

+/// Fold pattern:
+///   %sel1 = select i1 %c1, T, F
+///   %sel2 = select i1 %c1, F, T
+///   %ret = select i1 %c2, %sel1, %sel2
+/// into:
+///   %xor = xor i1 %c1, %c2
+///   %ret = select i1 %xor, F, T
+///
+/// This handles the case where two selects with the same condition have
+/// swapped true/false values, and a third select chooses between them.
+static Instruction *foldSymmetricSelects(SelectInst &SI,
+                                         InstCombiner::BuilderTy &Builder) {
+  Value *CondVal = SI.getCondition();
+  Value *TrueVal = SI.getTrueValue();
+  Value *FalseVal = SI.getFalseValue();
+
+  // Both operands must be selects with the same condition but swapped values.
+  SelectInst *Sel1 = dyn_cast<SelectInst>(TrueVal);
+  SelectInst *Sel2 = dyn_cast<SelectInst>(FalseVal);
+  if (!Sel1 || !Sel2)
+    return nullptr;
+
+  // Check if the conditions are the same.
+  if (Sel1->getCondition() != Sel2->getCondition())
+    return nullptr;
+
+  // Check if the values are swapped: Sel1(T,F) and Sel2(F,T).
+  if (Sel1->getTrueValue() != Sel2->getFalseValue() ||
+      Sel1->getFalseValue() != Sel2->getTrueValue())
+    return nullptr;
+
+  // The inner and outer select conditions must have the same type to create XOR.
+  if (Sel1->getCondition()->getType() != CondVal->getType())
+    return nullptr;
+
+
+  // Profitability check: both inner selects should have exactly one use
+  // (the outer select), otherwise we can't eliminate them.
+  if (!Sel1->hasOneUse() || !Sel2->hasOneUse())
+    return nullptr;
+
+  // Create xor of the conditions.
+  Value *XorCond = Builder.CreateXor(Sel1->getCondition(), CondVal);
+
+  // Create the new select: select (xor c1 c2), F, T
+  return SelectInst::Create(XorCond, Sel1->getFalseValue(), Sel1->getTrueValue());
+}
+
 Instruction *InstCombinerImpl::foldSelectOfBools(SelectInst &SI) {
   Value *CondVal = SI.getCondition();
   Value *TrueVal = SI.getTrueValue();
@@ -3990,6 +4038,9 @@ Instruction *InstCombinerImpl::visitSelectInst(SelectInst &SI) {
   if (Instruction *I = foldNestedSelects(SI, Builder))
     return I;

+  if (Instruction *I = foldSymmetricSelects(SI, Builder))
+    return I;
+
   // Match logical variants of the pattern,
   // and transform them iff that gets rid of inversions.
   //   (~x) | y  -->  ~(x & (~y))

